const input = $input.first().json;
const cbq = input.callback_query;
if (cbq) {
  return [{ json: {
    type: 'callback',
    chatId: cbq.message.chat.id,
    callbackId: cbq.id,
    data: cbq.data || '',
    isVoice: false, text: '', fileId: null,
    fileName: null, fileMime: null, fileSize: 0
  }}];
}
const msg = input.message;
if (!msg) return [];
const chatId = msg.chat.id;
const text = msg.text || msg.caption || '';
const isVoice = !!msg.voice;

// Document or photo detection
const isDoc = !!msg.document;
const isPhoto = !!(msg.photo && msg.photo.length);
if (isDoc) {
  return [{ json: {
    type: 'file', chatId, isVoice: false, text,
    fileId: msg.document.file_id,
    fileName: msg.document.file_name || 'document',
    fileMime: msg.document.mime_type || '',
    fileSize: msg.document.file_size || 0,
    fileType: 'document',
    callbackId: null, data: null
  }}];
}
if (isPhoto) {
  const best = msg.photo[msg.photo.length - 1];
  return [{ json: {
    type: 'file', chatId, isVoice: false, text,
    fileId: best.file_id,
    fileName: 'photo_' + Date.now() + '.jpg',
    fileMime: 'image/jpeg',
    fileSize: best.file_size || 0,
    fileType: 'photo',
    callbackId: null, data: null
  }}];
}

if (!isVoice && !text) return [];
const isStart = text === '/start' || text === '/menu';
const isAdmin = /^\/курсы|^\/добавить |^\/удалить |^\/промпт|^\/myid/i.test(text);
if (isAdmin) return [{ json: { type: 'admin', chatId, text, isVoice: false, fileId: null, fileName: null, fileMime: null, fileSize: 0, callbackId: null, data: null } }];
return [{ json: {
  type: isStart ? 'start' : (isVoice ? 'voice' : 'text'),
  chatId, isVoice, text,
  fileId: isVoice ? msg.voice.file_id : null,
  fileName: null, fileMime: null, fileSize: 0,
  callbackId: null, data: null
}}];

const { chatId, callbackId, data } = $input.first().json;
const [prefix, value] = (data || 'section:chat').split(':');
const section = value || 'chat';
const store = $getWorkflowStaticData('global');
if (!store.sessions) store.sessions = {};
store.sessions[String(chatId)] = { section, isAgent: prefix === 'agent' };
const names = {
  tasks:'📋 Задачи', notes:'📝 Заметки',
  sport:'🏋️ Спорт', work:'💼 Работа',
  ideas:'💡 Идеи', app:'🌐 Приложение',
  producer:'🎬 Продюсер', writer:'✍️ Сценарист',
  editor:'🎥 Монтажёр', sales:'💰 Продажник'
};
return [{ json: { chatId, callbackId, section, sectionName: names[section] || section } }];

const chatId = $('Router').item.json.chatId;
const text = $input.first().json.text;
const store = $getWorkflowStaticData('global');
const section = store.sessions?.[String(chatId)]?.section || 'chat';
const prompts = {
  chat:'Ты умный персональный ассистент по имени Зевс. Пользователя зовут Денис, обращайся к нему «Мой господин». Отвечай кратко, по-русски, дружелюбно. Без лишних вводных слов.',
  tasks:'Ты ассистент Зевс по задачам. Пользователя зовут Денис, «Мой господин». Помогай с задачами и приоритетами. Кратко, по-русски.',
  notes:'Ты ассистент Зевс по заметкам. Пользователя зовут Денис, «Мой господин». Структурируй идеи и мысли. Кратко, по-русски.',
  sport:'Ты фитнес-ассистент Зевс. Пользователя зовут Денис, «Мой господин». Тренировки, калории, питание. Кратко, по-русски.',
  work:'Ты бизнес-ассистент Зевс. Пользователя зовут Денис, «Мой господин». Рабочие задачи и проекты. Кратко, по-русски.',
  ideas:'Ты творческий ассистент Зевс. Пользователя зовут Денис, «Мой господин». Принимай идеи, структурируй. Кратко, по-русски.',
  producer:'Ты ИИ-агент «Продюсер». Помогаешь Денису (обращайся «Мой господин») с продюсированием контента: стратегия, монетизация, аудитория, планирование. Конкретные советы, по-русски.',
