};
return [{ json: { chatId, userText: text, isVoice: true, systemPrompt: prompts[section] || prompts.chat } }];

const d = $input.first().json;
const store = $getWorkflowStaticData('global');
const session = store.sessions?.[String(d.chatId)] || {};
const section = session.section || 'chat';
const prompts = {
  chat:'Ты умный персональный ассистент по имени Зевс. Пользователя зовут Денис, обращайся к нему «Мой господин». Отвечай кратко, по-русски, дружелюбно. Без лишних вводных слов.\n\nФАЙЛЫ: Если пользователь просит найти, скинуть, отправить файл или документ — вставь в ответ тег [FILE_SEARCH: запрос]. Например: «скинь КП» → [FILE_SEARCH: КП].\nПОЧТА: Если пользователь спрашивает про письмо, почту, email — вставь тег [EMAIL_CONTEXT: запрос]. Например: «что за письмо пришло?» → [EMAIL_CONTEXT: последнее]. «письмо от банка» → [EMAIL_CONTEXT: банк].',
  tasks:'Ты ассистент Зевс по задачам. Пользователя зовут Денис, «Мой господин». Помогай с задачами и приоритетами. Кратко, по-русски.',
  notes:'Ты ассистент Зевс по заметкам. Пользователя зовут Денис, «Мой господин». Структурируй идеи и мысли. Кратко, по-русски.',
  sport:'Ты фитнес-ассистент Зевс. Пользователя зовут Денис, «Мой господин». Тренировки, калории, питание. Кратко, по-русски.',
  work:'Ты бизнес-ассистент Зевс. Пользователя зовут Денис, «Мой господин». Рабочие задачи и проекты. Кратко, по-русски.\n\nФАЙЛЫ: Если пользователь просит найти, скинуть файл — вставь тег [FILE_SEARCH: запрос] в конце ответа.',
  ideas:'Ты творческий ассистент Зевс. Пользователя зовут Денис, «Мой господин». Принимай идеи, структурируй. Кратко, по-русски.',
  producer:'Ты ИИ-агент «Продюсер». Помогаешь Денису (обращайся «Мой господин») с продюсированием контента: стратегия, монетизация, аудитория, планирование. Конкретные советы, по-русски.',
  writer:'Ты ИИ-агент «Сценарист». Помогаешь Денису (обращайся «Мой господин») писать сценарии, скрипты, тексты для видео. Структура: крючок — суть — CTA. По-русски.',
  editor:'Ты ИИ-агент «Монтажёр». Помогаешь Денису (обращайся «Мой господин») с монтажом и постпродакшном: тайминг, переходы, цвет, структура ролика. По-русски.',
  sales:'Ты ИИ-агент «Продажник». Помогаешь Денису (обращайся «Мой господин») с продажами: скрипты, офферы, работа с возражениями, воронки. По-русски.'
};
return [{ json: { chatId: d.chatId, userText: d.text, isVoice: false, systemPrompt: prompts[section] || prompts.chat } }];

const res = $input.first().json;
const text = res.choices?.[0]?.message?.content || 'Не удалось получить ответ';
const chatId = $('Router').item.json.chatId;
const isVoice = $('Router').item.json.isVoice;
return [{ json: { chatId, text, isVoice } }];

const { chatId, text } = $input.first().json;
const store = $getWorkflowStaticData('global');
if (!store.siteConfig) store.siteConfig = {};
if (!store.siteConfig.courses) store.siteConfig.courses = [];

let reply = '';

// /курсы — show courses list
if (/^\/курсы/i.test(text)) {
  if (!store.siteConfig.courses.length) { reply = '📋 Курсов пока нет.'; }
  else { reply = '📋 *Курсы Студии ЧЕ:*\n\n' + store.siteConfig.courses.map((c,i) => `${i+1}. "${c.name}" — ${c.price}${c.level?' ('+c.level+')':''}`).join('\n'); }
}
// /добавить Название — 9990 ₽ (уровень)
else if (/^\/добавить /i.test(text)) {
  const raw = text.replace(/^\/добавить /i, '').trim();
  const m = raw.match(/^(.+?)\s*—\s*([\d\s]+[₽руб.]+.*)$/i);
  if (!m) { reply = '⚠️ Формат: /добавить Название курса — 9 990 ₽'; }
  else {
    const name = m[1].trim();
    const price = m[2].trim();
    store.siteConfig.courses.push({ name, price });
    reply = `✅ Добавлен курс:\n"${name}" — ${price}`;
  }
}
// /удалить Название
else if (/^\/удалить /i.test(text)) {
  const name = text.replace(/^\/удалить /i, '').trim().toLowerCase();
  const before = store.siteConfig.courses.length;
  store.siteConfig.courses = store.siteConfig.courses.filter(c => !c.name.toLowerCase().includes(name));
  const removed = before - store.siteConfig.courses.length;
  reply = removed ? `🗑 Удалено курсов: ${removed}` : '⚠️ Курс не найден. Проверь название.';
}
// /промпт — show base prompt
else if (/^\/промпт/i.test(text)) {
  const p = store.siteConfig.basePrompt || '(не задан)';
  reply = '📝 *Системный промпт бота:*\n\n' + p.slice(0, 3000);
}
// /myid — get telegram chat id
else if (/^\/myid/i.test(text)) {
  reply = '🆔 Твой chat id: ' + chatId;
}

return [{ json: { chatId, reply } }];

const fs = require('fs');
const path = require('path');
const ctx = $('Is File?').first().json;
const chatId = String(ctx.chatId);
const ts = Date.now();
const safeName = (ctx.fileName || 'file').replace(/[^a-zA-Z0-9а-яА-ЯёЁ._-]/g, '_');
const dir = '/files/' + chatId;

// Create directory if not exists
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

const filePath = dir + '/' + ts + '_' + safeName;

// Get binary data and write
const binaryData = $input.first().binary.fileData;
const buffer = Buffer.from(binaryData.data, 'base64');
fs.writeFileSync(filePath, buffer);

return [{ json: {
  chatId: ctx.chatId,
  fileId: 'f_' + ts,
  fileName: ctx.fileName,
  fileType: ctx.fileType || 'document',
  fileMime: ctx.fileMime || '',
  fileSize: ctx.fileSize || buffer.length,
  filePath: filePath,
  caption: ctx.text || '',
  ts: new Date().toISOString()
}}];

