const fs = require('fs');
const uploadUrl = $json.href;
if (!uploadUrl) {
  return [{ json: { ok: false, error: $json.error || 'No upload URL' } }];
}
const filePath = $('Save to Server').first().json.filePath;
const buffer = fs.readFileSync(filePath);

const resp = await $helpers.request({
  method: 'PUT',
  url: uploadUrl,
  body: buffer,
  headers: { 'Content-Type': 'application/octet-stream' },
  encoding: null
});

return [{ json: { ok: true, filePath: $('Save to Server').first().json.filePath, fileName: $('Save to Server').first().json.fileName } }];

const fs = require('fs');
const files = $json.files || [];
const chatId = $('Build Reply').first().json.chatId;
const botToken = $env.TELEGRAM_BOT_TOKEN;

if (!files.length) {
  // No files found — send text message
  const resp = await $helpers.request({
    method: 'POST',
    url: 'https://api.telegram.org/bot' + botToken + '/sendMessage',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: chatId, text: '🔍 Файл не найден. Попробуй другой запрос.' })
  });
  return [{ json: { ok: true, sent: 'not_found' } }];
}

const f = files[0];
// Read file from disk and send as document
try {
  const buffer = fs.readFileSync(f.path);
  const base64 = buffer.toString('base64');

  // Use n8n binary helper to send
  const FormData = require('form-data');
  const form = new FormData();
  form.append('chat_id', String(chatId));
  form.append('caption', '📎 ' + f.name + (f.description ? '\n' + f.description : ''));
  form.append('document', buffer, { filename: f.name, contentType: f.mime || 'application/octet-stream' });

  const resp = await $helpers.request({
    method: 'POST',
    url: 'https://api.telegram.org/bot' + botToken + '/sendDocument',
    headers: form.getHeaders(),
    body: form
  });
  return [{ json: { ok: true, sent: f.name } }];
} catch(e) {
  const resp = await $helpers.request({
    method: 'POST',
    url: 'https://api.telegram.org/bot' + botToken + '/sendMessage',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: chatId, text: '⚠️ Файл найден (' + f.name + '), но не могу отправить: ' + e.message })
  });
  return [{ json: { ok: false, error: e.message } }];
}
